// // This module implements a 16-bit shift register with load and shift operations.
// The shift register has a parallel load capability, allowing it to load a 16-bit input when the load signal is low.
// When the load signal is high, the register should shift left by one bit on each clock cycle. The least significant bit (LSB) should be filled with a specified value (0 or 1) during the shift operation.
module shift_register (
    input clk,
    input rst,
    input load,
    input [15:0] data_in,
    input msb_in,
    output reg [15:0] data_out
);

always @(posedge clk or posedge rst) begin
    if (rst) begin
        data_out <= 16'b0;
    end else if (load) begin
        data_out <= data_in;
    end else begin
        data_out <= {msb_in, data_out[15:1]};
    end
end

endmodule

